mapper.select:
SELECT e.id, e.order_id, e.user_id, u.nickname,u.avatar, e.shop_id, e.dish_score, e.service_score,
       e.environment_score, e.content, e.image_urls, e.create_time, p.id, p.name, p.price, oi.quantity, o.order_no,
       o.total_amount FROM evaluation e INNER JOIN `order` o ON e.order_id = o.id INNER JOIN order_item oi ON
  o.id = oi.order_id INNER JOIN product p ON oi.product_id = p.id INNER JOIN user u ON e.user_id = u.id WHERE p.id=#{ProductId}
ORDER BY e.create_time DESC;
